// ❌ BAD - trying to inherit from a sealed class; compile error
public class ExtendedString : string { } // compile error: cannot inherit sealed type

// ✅ GOOD - extension method adds methods without touching the sealed class
public static class StringExtensions {
    public static bool IsValidPostcode(this string s) =>
        System.Text.RegularExpressions.Regex.IsMatch(s, @"^[A-Z]{1,2}\d[A-Z\d]? ?\d[A-Z]{2}$");
}
// Usage on the sealed string type:
bool ok = addressLine.PostCode.IsValidPostcode();

// ❌ BAD - no index in foreach; developer uses a separate counter incorrectly
int index = 0;
foreach (var product in products) {
    Console.WriteLine($"{index}: {product.Name}");
    index++; // easy to forget; easy to increment in wrong place
}

// ✅ GOOD - LINQ Select with index: clean and idiomatic
foreach (var (product, i) in products.Select((p, i) => (p, i)))
    Console.WriteLine($"{i}: {product.Name}");

// ✅ GOOD - for loop when collection supports indexing
for (int i = 0; i < products.Count; i++)
    Console.WriteLine($"{i}: {products[i].Name}");

// C# 10 - file-scoped namespace, record struct
namespace ECommerceApp.Orders; // no braces
public record struct Money(decimal Amount, string Currency);

// C# 11 - raw string literal (no escaping needed)
var json = """
    { "name": "Alice", "role": "admin" }
    """;

// C# 12 - primary constructor and collection expression
public class Cart(IEnumerable<Product> products) {
    private readonly List<Product> _items = [.. products]; // collection expression
}

// ❌ BAD - Func runs in memory; EF loads all orders then filters
Func<Order, bool> filter = o => o.Total > 100;
var orders = db.Orders.AsEnumerable().Where(filter).ToList(); // SELECT * then filter in memory

// ✅ GOOD - Expression is translated to SQL by EF Core
Expression<Func<Order, bool>> filter = o => o.Total > 100;
var orders = db.Orders.Where(filter).ToList(); // SELECT ... WHERE Total > 100

// You can also compile and run a tree in memory
var compiled = filter.Compile();
bool matchesInMemory = compiled(new Order { Total = 150 }); // true

// ❌ BAD - Predicate<T> passed where Func<T,bool> is expected
Predicate<Order> isLarge = o => o.Total > 500;
var largeOrders = orders.Where(isLarge); // compile error - wrong delegate type

// ✅ GOOD - use Func<T,bool> for LINQ; Predicate<T> for older BCL methods
Func<Order, bool> isLarge = o => o.Total > 500;
Action<Order> notifyCustomer = o => _emailService.Send(o.CustomerEmail, "Order update");
Predicate<Order> isCancelled = o => o.Status == OrderStatus.Cancelled;

var large = orders.Where(isLarge).ToList();           // LINQ uses Func
var cancelled = orders.FindAll(isCancelled);          // List.FindAll uses Predicate
